export const internalDeleteManyMutation = (apiIdentifier: string) => {
  const capitalizedApiIdentifier = capitalize(apiIdentifier);
  return `
    ${internalErrorsDetails}
    
    mutation InternalDeleteMany${capitalizedApiIdentifier}(
      $search: String
      $filter: [${capitalizedApiIdentifier}Filter!]
    ) {
      ${internalHydrationPlan(apiIdentifier)}
      internal {
        deleteMany${capitalizedApiIdentifier}(search: $search, filter: $filter) {
          success
          errors {
            ... InternalErrorsDetails
          }
        }
      }
    }
  `;
};

export type RecordData = Record<string, any>;

export interface InternalFindOneOptions {
  /** Return only the given fields on the backend record (and related records) */
  select?: AnySelection;

  /** Raise an error if the record for the given id can't be found. Defaults to `true` */
  throwOnEmptyData?: boolean;
}

/**
 * Model specific manager for a given model's internal representation. Used to access the inner, raw data in the Gadget database. Use with caution -- it's easy to break stuff, and the Public API should be used when possible!
 */
export class InternalModelManager {
  private readonly capitalizedApiIdentifier: string;

  constructor(private readonly apiIdentifier: string, readonly connection: GadgetConnection) {
    this.capitalizedApiIdentifier = camelize(apiIdentifier);
  }

  /**
   * Find one record from the backend internal API
   *
   * @deprecated Please use the `options` method instead
   * @param id the id of the record to find
   * @param throwOnEmptyData whether to throw an error if the record can't be found. Default: `true`
   */
  async findOne(id: string, throwOnEmptyData?: boolean): Promise<GadgetRecord<RecordData>>;
  /**
   * Find one record from the backend internal API
   *
   * @param id the id of the record to find
   * @param options Options for the find. Optional.
   */
  async findOne(id: string, options?: InternalFindOneOptions): Promise<GadgetRecord<RecordData>>;
  async findOne(id: string, option?: boolean | InternalFindOneOptions): Promise<GadgetRecord<RecordData>> {
    const options: InternalFindOneOptions = typeof option === "boolean" ? { throwOnEmptyData: option } : option ?? {};
    options.throwOnEmptyData ??= true;

    const response = await this.connection.currentClient
      .query(internalFindOneQuery(this.apiIdentifier), { id, select: options.select })
      .toPromise();

    const assertSuccess = options.throwOnEmptyData ? assertOperationSuccess : assertNullableOperationSuccess;
    const result = assertSuccess(response, ["internal", this.apiIdentifier]);
    return await hydrateRecord(response, result);
  }

  /**
   * Find one record from the backend internal API. Returns null if the record can't be found.
   *
   * @param id the id of the record to find
   * @param options Options for the find. Optional.
   */
  async maybeFindOne(id: string, options?: InternalFindOneOptions): Promise<GadgetRecord<RecordData> | null> {
    const record = await this.findOne(id, options);
    return record.isEmpty() ? null : record;
  }

  /**
   * Find a list of records from the backend internal API.
   *
   * @param options Options for the find. Optional.
   */
  async findMany(options?: InternalFindManyOptions): Promise<GadgetRecordList<any>> {
    const plan = internalFindManyQuery(this.apiIdentifier, options);
    const response = await this.connection.currentClient.query(plan.query, plan.variables).toPromise();
    const connection = assertNullableOperationSuccess(response, ["internal", `list${this.capitalizedApiIdentifier}`]);
    const records = hydrateConnection(response, connection);

    return GadgetRecordList.boot(this, records, { options, pageInfo: connection.pageInfo });
  }

  /**
   * Find the first record from the backend that matches the given options using the Internal API. Throws if no record can be found.
   *
   * @param options Options for the find. Optional.
   */
  async findFirst(options?: InternalFindFilteredOptions, throwOnEmptyData = true): Promise<GadgetRecord<RecordShape>> {
    const plan = internalFindFirstQuery(this.apiIdentifier, options);
    const response = await this.connection.currentClient.query(plan.query, plan.variables).toPromise();

    let connection;
    if (throwOnEmptyData === false) {
      // If this is a nullable operation, don't throw errors on empty
      connection = assertNullableOperationSuccess(response, ["internal", `list${this.capitalizedApiIdentifier}`]);
    } else {
      // Otherwise, passthrough the `throwOnEmptyData` flag, to account for
      // `findMany` (allows empty arrays) vs `findFirst` (no empty result) usage.
      connection = assertOperationSuccess(response, ["internal", `list${this.capitalizedApiIdentifier}`], throwOnEmptyData);
    }

    const records = hydrateConnection(response, connection);
    const recordList = GadgetRecordList.boot(this, records, { options, pageInfo: connection.pageInfo });
    return recordList[0];
  }

  /**
   * Find the first record from the backend that matches the given options using the Internal API. Returns null if no record can be found
   *
   * @param options Options for the find. Optional.
   */
  async maybeFindFirst(options?: InternalFindFilteredOptions): Promise<GadgetRecord<RecordShape> | null> {
    return await this.findFirst(options, false);
  }

  /**
   * Creates a new record for this model using the Internal API.
   *
   * __Note__: This won't call the `create` action on the backend model as it uses the Internal API. Use the Public API if you want to call actions. See the Gadget docs for more on the differences between the Public API and the Internal API.
   *
   * @param record Raw record data to apply to the record.
   */
  async create(record: RecordData): Promise<GadgetRecord<RecordShape>> {
    return await this.transaction(async (transaction) => {
      const response = await transaction.client
        .mutation(internalCreateMutation(this.apiIdentifier), {
          record: record[this.apiIdentifier],
        })
        .toPromise();
      const result = assertMutationSuccess(response, ["internal", `create${this.capitalizedApiIdentifier}`]);
      return await hydrateRecord(response, result[this.apiIdentifier]);
    });
  }

  /**
   * Updates a given record with the given data using the Internal API.
   *
   * __Note__: This won't call the `update` action on the backend model as it uses the Internal API. Use the Public API if you want to call actions. See the Gadget docs for more on the differences between the Public API and the Internal API.
   *
   * @param id The id of the record to update
   * @param record Raw record data to apply to the record.
   */
  async update(id: string, record: RecordData): Promise<GadgetRecord<RecordShape>> {
    assert(id, `Can't update a record without an ID passed`);
    return await this.transaction(async (transaction) => {
      const response = await transaction.client
        .mutation(internalUpdateMutation(this.apiIdentifier), {
          id,
          record: record[this.apiIdentifier],
        })
        .toPromise();
      const result = assertMutationSuccess(response, ["internal", `update${this.capitalizedApiIdentifier}`]);

      return await hydrateRecord(response, result[this.apiIdentifier]);
    });
  }

  /**
   * Deletes a record by id from the backend database using the Internal API
   *
   * __Note__: This won't call the `delete` action on the backend model as it uses the Internal API. Use the Public API if you want to call actions. See the Gadget docs for more on the differences between the Public API and the Internal API.
   *
   * @param id The id of the record to delete
   */
  async delete(id: string): Promise<void> {
    assert(id, `Can't delete a record without an ID`);
    return await this.transaction(async (transaction) => {
      const response = await transaction.client.mutation(internalDeleteMutation(this.apiIdentifier), { id }).toPromise();
      assertMutationSuccess(response, ["internal", `delete${this.capitalizedApiIdentifier}`]);
    });
  }

  /**
   * Deletes all the records matching the given filter conditions from the backend database using the internal API
   *
   * __Note__: This won't call the `delete` action on the backend model as it uses the Internal API. Use the Public API if you want to call actions. See the Gadget docs for more on the differences between the Public API and the Internal API.
   *
   * @param id The id of the record to delete
   */
  async deleteMany(options?: { filter?: AnyFilter | null }): Promise<void> {
    return await this.transaction(async (transaction) => {
      const response = await transaction.client.mutation(internalDeleteManyMutation(this.apiIdentifier), options).toPromise();
      assertMutationSuccess(response, ["internal", `deleteMany${this.capitalizedApiIdentifier}`]);
    });
  }

  /**
   * Starts or continues a transaction against the backend API.
   */
  async transaction<T>(callback: (transaction: GadgetTransaction) => Promise<T>): Promise<T> {
    return await this.connection.transaction(callback);
  }
}
